### RxDB Local Database Setup (JavaScript)

Source: https://github.com/pubkey/rxdb/blob/master/docs/articles/zero-latency-local-first.html

Sets up a local RxDB database instance using localstorage for storage. It defines a 'tasks' collection with a specific schema and subscribes to changes in the 'tasks' collection to log updates. This allows for near-zero delay reads and writes locally.

```javascript
import { createRxDatabase } from 'rxdb/plugins/core';
import { getRxStorageLocalstorage } from 'rxdb/plugins/storage-localstorage';

async function initZeroLocalDB() {
  // Create a local RxDB instance using localstorage-based storage
  const db = await createRxDatabase({
    name: 'myZeroLocalDB',
    storage: getRxStorageLocalstorage(),
    // optional: password for encryption if needed
  });

  // Define one or more collections
  await db.addCollections({
    tasks: {
      schema: {
        title: 'task schema',
        version: 0,
        type: 'object',
        primaryKey: 'id',
        properties: {
          id:       { type: 'string', maxLength: 100 },
          title:    { type: 'string' },
          done:     { type: 'boolean' }
        }
      }
    }
  });

  // Reactive query - automatically updates on local or remote changes
  db.tasks
    .find()
    .$ // returns an RxJS Observable
    .subscribe(allTasks => {
      console.log('All tasks updated:', allTasks);
    });

  return db;
}
```

