### RxDB: Create and Observe Offline Database (JavaScript)

Source: https://github.com/pubkey/rxdb/blob/master/docs/articles/offline-database.html

Demonstrates how to create an RxDB database, add a collection with a defined schema, and subscribe to real-time changes for a specific query. This snippet utilizes the localStorage storage plugin for simplicity. It's a foundational example for building offline-first applications.

```javascript
import { createRxDatabase } from 'rxdb/plugins/core';
import { getRxStorageLocalstorage } from 'rxdb/plugins/storage-localstorage';

async function initDB() {
  // Create a local offline database
  const db = await createRxDatabase({
    name: 'myOfflineDB',
    storage: getRxStorageLocalstorage()
  });

  // Add collections
  await db.addCollections({
    tasks: {
      schema: {
        title: 'tasks schema',
        version: 0,
        type: 'object',
        primaryKey: 'id',
        properties: {
          id: { type: 'string' },
          title: { type: 'string' },
          done: { type: 'boolean' }
        }
      }
    }
  });

  // Observe changes in real time
  db.tasks
    .find({ selector: { done: false } })
    .$ // returns an observable that emits whenever the result set changes
    .subscribe(undoneTasks => {
      console.log('Currently undone tasks:', undoneTasks);
    });

  return db;
}
```

